module RefModule(
	input J, K, Clk,
	output reg Q,
	output Q_b
    );assign Q_b = ~Q;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge Clk or posedge dbg_halt)

	case ({J,K})
		2'b00: Q <= Q;
		2'b01: Q <= 1'b0;
		2'b10: Q <= 1'b1;
		2'b11: Q <= !Q;
	endcase

endmodule
